import React, { useState, useEffect } from 'react';
import './CommandeForm.css';


const CommandeForm = ({ onSubmit, onDelete, selectedCommande, clients, articles }) => {
  const [formData, setFormData] = useState({
    idCOM: '',
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });

  useEffect(() => {
    if (selectedCommande) {
      setFormData(selectedCommande);
    } else {
      setFormData({
        idCOM: '',
        codeCli: '',
        codeArt: '',
        dateCom: '',
        QteCom: ''
      });
    }
  }, [selectedCommande]);

  const handleChange = e => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = e => {
    e.preventDefault();
    onSubmit(formData);
  };

  const handleDelete = () => {
    onDelete(formData.idCOM);
  };

  return (
    <form className="commande-form" onSubmit={handleSubmit}>
      <input
        type="text"
        name="idCOM"
        placeholder="ID Commande"
        value={formData.idCOM}
        onChange={handleChange}
        required
      />

      <select
        name="codeCli"
        value={formData.codeCli}
        onChange={handleChange}
        required
      >
        <option value="">-- Sélectionner un client --</option>
        {clients.map(cli => (
          <option key={cli.codeCli} value={cli.codeCli}>
            {cli.nomCli} {cli.prenomCli}
          </option>
        ))}
      </select>

      <select
        name="codeArt"
        value={formData.codeArt}
        onChange={handleChange}
        required
      >
        <option value="">-- Sélectionner un article --</option>
        {articles.map(art => (
          <option key={art.codeArt} value={art.codeArt}>
            {art.nomArt}
          </option>
        ))}
      </select>

      <input
        type="date"
        name="dateCom"
        value={formData.dateCom}
        onChange={handleChange}
        required
      />

      <input
        type="number"
        name="QteCom"
        placeholder="Quantité"
        min="1"
        value={formData.QteCom}
        onChange={handleChange}
        required
      />

      <button type="submit">
        {selectedCommande ? 'Modifier' : 'Ajouter'}
      </button>

      {selectedCommande && (
        <button
          type="button"
          onClick={handleDelete}
          style={{ backgroundColor: '#dc3545', marginTop: '10px' }}
        >
          Supprimer
        </button>
      )}
    </form>
  );
};

export default CommandeForm;
